  if (!value) return "";
  var d, m, y;

  // Trường hợp 1: Nếu Excel trả về đối tượng Date (khi dùng cellDates: true)
  if (value instanceof Date) {
    if (isNaN(value.getTime())) return "";
    d = value.getDate();
    m = value.getMonth() + 1;
    y = value.getFullYear();
  }
  // Trường hợp 2: Nếu là số Serial của Excel (ví dụ: 44197)
  else if (typeof value === 'number') {
    var date = new Date((value - 25569) * 86400 * 1000);
    d = date.getDate();
    m = date.getMonth() + 1;
    y = date.getFullYear();
  }
  // Trường hợp 3: Nếu là chuỗi (String)
  else if (typeof value === 'string') {
    // Tách chuỗi theo dấu - hoặc /
    var parts = value.split(/[-/]/);
    if (parts.length === 3) {
      // Kiểm tra xem là định dạng DD-MM-YYYY hay YYYY-MM-DD
      if (parts[0].length === 4) {
        // YYYY-MM-DD
        y = parts[0];
        m = parts[1];
        d = parts[2];
      } else {
        // DD-MM-YYYY
        d = parts[0];
        m = parts[1];
        y = parts[2];
      }
    } else {
      // Nếu chuỗi lạ, thử cho Date parse
      var _date = new Date(value);
      if (isNaN(_date.getTime())) return "";
      d = _date.getDate();
      m = _date.getMonth() + 1;
      y = _date.getFullYear();
    }
  }

  // Đảm bảo trả về đúng định dạng DD-MM-YYYY (thêm số 0 phía trước)
  var day = String(d).padStart(2, '0');
  var month = String(m).padStart(2, '0');
  var year = String(y);

  // Kiểm tra xem các giá trị có phải là số hợp lệ không
  if (day === "NaN" || month === "NaN" || year === "NaN") return "";
  return "".concat(day, "-").concat(month, "-").concat(year);
}
